#!/usr/bin/env bash
# Freddy Fix It — apply-seo-services.sh  (SUPERSET; run ONLY this newest installer)
#   bash ~/Desktop/freddy-fixit/apply-seo-services.sh
set -e
# Target = the folder this script lives in (your repo), so it works wherever the repo is.
TARGET="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
if [ ! -d "$TARGET/.git" ]; then echo "❌ $TARGET is not a git repo. Put this script inside your freddy-fixit project folder."; exit 1; fi
b64dec(){ if base64 --decode >/dev/null 2>&1 <<< "QQ=="; then base64 --decode > "$1"; else base64 -D > "$1"; fi; }
write(){ mkdir -p "$TARGET/$(dirname "$1")"; b64dec "$TARGET/$1"; echo "  ✓ $1"; }
echo "Applying SEO + service-page update to $TARGET ..."
